package com.theyawns.framework.persistence.postgres.repository;

import com.theyawns.framework.persistence.postgres.entity.OutboxEntity;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.stereotype.Repository;

import java.util.List;
import java.util.Optional;

/**
 * Spring Data JPA repository for the {@code domain_outbox} table.
 *
 * @author Generated by Claude Code
 * @since 3.0
 */
@Repository
public interface OutboxRepository extends JpaRepository<OutboxEntity, String> {

    /**
     * Finds an outbox entry by event ID.
     *
     * @param eventId the event ID
     * @return the entity if found
     */
    Optional<OutboxEntity> findByEventId(String eventId);

    /**
     * Finds all event IDs where the status is not DELIVERED.
     * Used for EAGER initial load to recover pending entries on restart.
     *
     * @return event IDs of non-delivered entries
     */
    @Query("SELECT o.eventId FROM OutboxEntity o WHERE o.status <> 'DELIVERED'")
    List<String> findAllNonDeliveredEventIds();
}
